/**
 * Classical music synonym expansion for local collection/wantlist search.
 *
 * Each group contains equivalent terms across languages. When a search term
 * contains any entry from a group, variants are generated by substituting
 * each *other* entry from that group. Groups are applied independently
 * (no cross-product) to keep variant count linear.
 */
const SYNONYM_GROUPS = [
    // Work types
    ["Symphony", "Sinfonie", "Symphonie", "Симфония", "Sinfonia", "Szimfónia"],
    ["Concerto", "Konzert", "Концерт", "Concierto"],
    ["Sonata", "Sonate", "Соната"],
    ["Overture", "Ouverture", "Ouvertüre", "Увертюра", "Ouvertür"],
    ["Quartet", "Quartett", "Quatuor", "Квартет", "Cuarteto"],
    ["Quintet", "Quintett", "Quintette", "Квинтет"],
    ["Suite", "Сюита"],
    ["Prelude", "Prélude", "Прелюдия", "Preludio"],
    ["Fugue", "Fuge", "Фуга", "Fuga"],
    ["Etude", "Étude", "Etüde", "Этюд"],
    ["Nocturne", "Notturno", "Ноктюрн"],
    ["Requiem", "Реквием"],
    ["Mass", "Messe", "Messa", "Месса"],
    ["Variations", "Variationen", "Вариации", "Variaciones"],
    ["Trio", "Трио"],
    ["Rhapsody", "Rhapsodie", "Рапсодия", "Rapsodia"],
    ["Serenade", "Серенада", "Serenata"],
    ["Waltz", "Walzer", "Вальс", "Valse"],
    ["Polonaise", "Полонез"],
    ["Mazurka", "Мазурка"],
    ["Ballade", "Баллада", "Ballad"],
    ["Scherzo", "Скерцо"],
    ["Impromptu", "Экспромт"],
    ["Cantata", "Kantate", "Кантата"],
    ["Oratorio", "Oratorium", "Оратория"],
    ["Opera", "Опера", "Oper"],
    ["Fantasia", "Fantasie", "Фантазия", "Fantasy"],
    // Numbering styles
    ["No.", "Nr.", "N°", "№", "Nº"],
    // Opus notations
    ["Op.", "Opus"],
    ["K.", "KV", "Köchel", "Kochel"],
    ["BWV", "Bach-Werke-Verzeichnis"],
    ["D.", "Deutsch"],
    ["Hob.", "Hoboken"],
    // Key quality
    ["major", "Dur", "мажор", "majeur", "maggiore"],
    ["minor", "Moll", "минор", "mineur", "minore"],
    // Enharmonic key names — avoid short entries that false-match inside words
    ["C sharp", "Cis", "C#", "do dièse"],
    ["D flat", "Des", "Db", "ré bémol"],
    ["E flat", "Es", "Eb", "mi bémol"],
    ["F sharp", "Fis", "F#", "fa dièse"],
    ["G flat", "Ges", "Gb", "sol bémol"],
    ["A flat", "As", "Ab", "la bémol"],
    ["B flat", "Bb", "si bémol"],
    // Ordinals (1st through 9th)
    ["First", "Erste", "Первая", "1st", "Premier", "Première", "Prima"],
    ["Second", "Zweite", "Вторая", "2nd", "Deuxième", "Seconda"],
    ["Third", "Dritte", "Третья", "3rd", "Troisième", "Terza"],
    ["Fourth", "Vierte", "Четвёртая", "4th", "Quatrième", "Quarta"],
    ["Fifth", "Fünfte", "Пятая", "5th", "Cinquième", "Quinta"],
    ["Sixth", "Sechste", "Шестая", "6th", "Sixième", "Sesta"],
    ["Seventh", "Siebte", "Седьмая", "7th", "Septième", "Settima"],
    ["Eighth", "Achte", "Восьмая", "8th", "Huitième", "Ottava"],
    ["Ninth", "Neunte", "Девятая", "9th", "Neuvième", "Nona"],
];
// Pre-build a lowercase lookup for fast matching
const GROUPS_LOWER = SYNONYM_GROUPS.map((g) => ({
    original: g,
    lower: g.map((t) => t.toLowerCase()),
}));
/**
 * Expand a search term by substituting classical-music synonyms.
 *
 * Returns `variants` (the alternative search strings) and `applied`
 * (human-readable descriptions of what was expanded, for UI display).
 *
 * Each synonym group is applied independently — no cross-product.
 * For "Symphony No. 5" this yields ~10 variants, not hundreds.
 */
export function expandWithSynonyms(term) {
    const termLower = term.toLowerCase();
    const variants = new Set();
    const applied = [];
    for (const group of GROUPS_LOWER) {
        // Find which entry (if any) appears in the term at a word boundary.
        // A match must start at position 0 or be preceded by a non-letter,
        // and must end at the string end or be followed by a non-letter
        // (digits and punctuation are OK boundaries). This prevents
        // "Mass" matching inside "Massive" or "Ab" inside "Abbey".
        let matchIdx = -1;
        let matchPos = -1;
        let matchLen = 0;
        for (let i = 0; i < group.lower.length; i++) {
            const entry = group.lower[i];
            let searchFrom = 0;
            while (searchFrom < termLower.length) {
                const pos = termLower.indexOf(entry, searchFrom);
                if (pos === -1)
                    break;
                const end = pos + entry.length;
                // Check word boundaries (letters only — digits/punct are OK boundaries)
                const beforeOk = pos === 0 || !/\p{L}/u.test(termLower[pos - 1]);
                const afterOk = end === termLower.length || !/\p{L}/u.test(termLower[end]);
                if (beforeOk && afterOk && entry.length > matchLen) {
                    matchIdx = i;
                    matchPos = pos;
                    matchLen = entry.length;
                    break; // found a valid boundary match for this entry
                }
                searchFrom = pos + 1; // try next occurrence
            }
        }
        if (matchIdx === -1)
            continue;
        // Generate variants by replacing the matched substring with each other entry
        const before = term.slice(0, matchPos);
        const after = term.slice(matchPos + matchLen);
        const others = [];
        for (let i = 0; i < group.original.length; i++) {
            if (i === matchIdx)
                continue;
            const variant = before + group.original[i] + after;
            variants.add(variant);
            others.push(group.original[i]);
        }
        if (others.length) {
            applied.push(`${group.original[matchIdx]} → ${others.join(", ")}`);
        }
    }
    return { variants: [...variants], applied };
}
